import React, { useState, useEffect } from 'react'; // Thêm useState và useEffect
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import LoginPage from './pages/LoginPage';
import Dashboard from './pages/Dashboard';
import UserListPage from './pages/UserListPage';
import CustomerListPage from './pages/CustomerListPage';
import KhaiBaoCoSo from './pages/KhaiBaoCoSo';
import LogoutPage from './pages/LogoutPage';
import Sidebar from './components/Sidebar';
import FarmDetail from './pages/FarmDetail';
import FarmListPage from './pages/FarmListPage';
import './Dashboard.css';

function App() {
  // Khởi tạo state token và role từ localStorage
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [role, setRole] = useState(localStorage.getItem('role'));

  // Hàm này sẽ được truyền xuống LoginPage để cập nhật token và role
  const handleSetAuthStatus = (newToken, newRole) => {
    localStorage.setItem('token', newToken);
    localStorage.setItem('role', newRole);
    setToken(newToken); // Cập nhật state token
    setRole(newRole);   // Cập nhật state role
  };

  // Sử dụng useEffect để đồng bộ state với localStorage khi App khởi tạo hoặc khi token/role thay đổi bên ngoài
  // Mặc dù chúng ta đang quản lý bằng handleSetAuthStatus, việc này giúp đảm bảo tính nhất quán
  useEffect(() => {
    setToken(localStorage.getItem('token'));
    setRole(localStorage.getItem('role'));
  }, []); // Chạy một lần khi component mount

  // Log để kiểm tra giá trị token và role trong App.js khi render
  console.log('App.js render: token =', token);
  console.log('App.js render: role =', role);

  return (
    <Router>
      <div className="app-container">
        {token && <Sidebar />}

        <div className="main-layout-content">
          <div className="main-header-banner">
            <img src="/logo_kiemlam.png" alt="Logo Chi cục Kiểm Lâm" className="header-logo" />
            <div className="header-text">
              <h1>CHI CỤC KIỂM LÂM - SỞ NÔNG NGHIỆP VÀ MÔI TRƯỜNG</h1>
              <h2>QUẢN LÝ LÂM SẢN</h2>
              <h3 className="header-copyright" translate="no">Software copyright: Nguyen Van Phuc</h3>
            </div>
          </div>

          <div className="route-content-wrapper">
            <Routes>
              {/* Truyền hàm handleSetAuthStatus xuống LoginPage */}
              <Route path="/" element={<LoginPage setAuthStatus={handleSetAuthStatus} />} />

              {/* Các ROUTE CÓ BẢO VỆ */}
              <Route path="/dashboard" element={token ? <Dashboard /> : <Navigate to="/" />} />
              <Route path="/khai-bao" element={token ? <KhaiBaoCoSo /> : <Navigate to="/" />} />
              <Route path="/admin/farms" element={token && role === 'admin' ? <FarmListPage /> : <Navigate to="/" />} />
              <Route path="/farm-details/:farmId" element={token ? <FarmDetail /> : <Navigate to="/" />} />
              <Route path="/admin/users" element={token && role === 'admin' ? <UserListPage /> : <Navigate to="/" />} />
              <Route path="/admin/customers" element={token && role === 'admin' ? <CustomerListPage /> : <Navigate to="/" />} />
              {/* Đối với LogoutPage, chúng ta cũng nên reset token và role trong App state */}
              <Route path="/logout" element={<LogoutPage setAuthStatus={handleSetAuthStatus} />} />
            </Routes>
          </div>
        </div>

        <div className="app-copyright" translate="no">
          Phiên bản 1.0.0 | &copy; 2023 Nguyen Van Phuc
        </div>
      </div>
    </Router>
  );
}

export default App;
